import React, { useState } from "react";
import { useSelector, useDispatch } from "react-redux";
import { Redirect } from "react-router-dom";
import authService from "../services/auth.service";
import UserService from "../services/user.service";
import { updateItemsPerPage } from "../slices/auth";

const ALLOWED_PAGE_SIZES = [10, 20, 50, 100];

const Profile = () => {
  const { user: currentUser } = useSelector((state) => state.auth);
  const dispatch = useDispatch();

  const [currentPassword, setCurrentPassword] = useState("");
  const [newPassword, setNewPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [message, setMessage] = useState("");
  const [isError, setIsError] = useState(false);
  const [loading, setLoading] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [showCurrentPw, setShowCurrentPw] = useState(false);
  const [showNewPw, setShowNewPw] = useState(false);
  const [showConfirmPw, setShowConfirmPw] = useState(false);
  const [savingPreference, setSavingPreference] = useState(false);
  const [prefMessage, setPrefMessage] = useState("");

  if (!currentUser) {
    return <Redirect to="/login" />;
  }

  const handleChangePassword = (e) => {
    e.preventDefault();
    setMessage("");
    setIsError(false);

    if (newPassword.length < 6) {
      setMessage("New password must be at least 6 characters.");
      setIsError(true);
      return;
    }

    if (newPassword !== confirmPassword) {
      setMessage("New password and confirm password do not match.");
      setIsError(true);
      return;
    }

    setLoading(true);
    authService
      .changePassword(currentPassword, newPassword)
      .then(() => {
        setMessage("Password changed successfully!");
        setIsError(false);
        setCurrentPassword("");
        setNewPassword("");
        setConfirmPassword("");
        setTimeout(() => setShowForm(false), 2000);
      })
      .catch((err) => {
        const msg =
          err.response?.data?.message ||
          "Failed to change password. Please try again.";
        setMessage(msg);
        setIsError(true);
      })
      .finally(() => setLoading(false));
  };

  const handleItemsPerPageChange = (newValue) => {
    setSavingPreference(true);
    setPrefMessage("");
    UserService.updatePreferences({ itemsPerPage: newValue })
      .then(() => {
        dispatch(updateItemsPerPage(newValue));
        setPrefMessage("Saved!");
        setTimeout(() => setPrefMessage(""), 2000);
      })
      .catch((err) => {
        setPrefMessage(err.response?.data?.message || "Failed to save.");
      })
      .finally(() => setSavingPreference(false));
  };

  return (
    <div className="container" style={{ maxWidth: 600 }}>
      <div className="card shadow-sm mb-4">
        <div
          className="card-header text-white"
          style={{
            background: "linear-gradient(135deg, #4a90d9, #357abd)",
          }}
        >
          <h5 className="mb-0">
            <span role="img" aria-label="profile">
              👤
            </span>{" "}
            {currentUser.username}'s Profile
          </h5>
        </div>
        <div className="card-body">
          <p className="mb-2">
            <strong>Email:</strong> {currentUser.email}
          </p>
          <p className="mb-0">
            <strong>Roles:</strong>{" "}
            {currentUser.roles &&
              currentUser.roles.map((r) => r.replace("ROLE_", "")).join(", ")}
          </p>
        </div>
      </div>

      {/* Change Password Section */}
      <div className="card shadow-sm">
        <div className="card-header d-flex justify-content-between align-items-center">
          <h6 className="mb-0">
            <span role="img" aria-label="lock">
              🔒
            </span>{" "}
            Change Password
          </h6>
          <button
            className={`btn btn-sm ${showForm ? "btn-outline-secondary" : "btn-outline-primary"}`}
            onClick={() => {
              setShowForm(!showForm);
              setMessage("");
            }}
          >
            {showForm ? "Cancel" : "Change"}
          </button>
        </div>

        {showForm && (
          <div className="card-body">
            {message && (
              <div
                className={`alert ${isError ? "alert-danger" : "alert-success"} py-2`}
                role="alert"
              >
                {message}
              </div>
            )}
            <form onSubmit={handleChangePassword}>
              <div className="form-group mb-3">
                <label htmlFor="currentPassword">Current Password</label>
                <div className="password-wrapper">
                  <input
                    type={showCurrentPw ? "text" : "password"}
                    id="currentPassword"
                    className="form-control"
                    placeholder="Enter current password"
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    required
                  />
                  <button
                    type="button"
                    className="password-toggle"
                    onClick={() => setShowCurrentPw(!showCurrentPw)}
                    tabIndex={-1}
                  >
                    {showCurrentPw ? (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                        <line x1="2.5" y1="2.5" x2="13.5" y2="13.5" />
                      </svg>
                    ) : (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                      </svg>
                    )}
                  </button>
                </div>
              </div>
              <div className="form-group mb-3">
                <label htmlFor="newPassword">New Password</label>
                <div className="password-wrapper">
                  <input
                    type={showNewPw ? "text" : "password"}
                    id="newPassword"
                    className="form-control"
                    placeholder="At least 6 characters"
                    value={newPassword}
                    onChange={(e) => setNewPassword(e.target.value)}
                    required
                    minLength={6}
                  />
                  <button
                    type="button"
                    className="password-toggle"
                    onClick={() => setShowNewPw(!showNewPw)}
                    tabIndex={-1}
                  >
                    {showNewPw ? (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                        <line x1="2.5" y1="2.5" x2="13.5" y2="13.5" />
                      </svg>
                    ) : (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                      </svg>
                    )}
                  </button>
                </div>
              </div>
              <div className="form-group mb-3">
                <label htmlFor="confirmPassword">Confirm New Password</label>
                <div className="password-wrapper">
                  <input
                    type={showConfirmPw ? "text" : "password"}
                    id="confirmPassword"
                    className="form-control"
                    placeholder="Re-enter new password"
                    value={confirmPassword}
                    onChange={(e) => setConfirmPassword(e.target.value)}
                    required
                    minLength={6}
                  />
                  <button
                    type="button"
                    className="password-toggle"
                    onClick={() => setShowConfirmPw(!showConfirmPw)}
                    tabIndex={-1}
                  >
                    {showConfirmPw ? (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                        <line x1="2.5" y1="2.5" x2="13.5" y2="13.5" />
                      </svg>
                    ) : (
                      <svg
                        width="16"
                        height="16"
                        viewBox="0 0 16 16"
                        fill="none"
                        stroke="currentColor"
                        strokeWidth="1.5"
                        strokeLinecap="round"
                        strokeLinejoin="round"
                      >
                        <path d="M2 8s2.5-4.5 6-4.5S14 8 14 8s-2.5 4.5-6 4.5S2 8 2 8z" />
                        <circle cx="8" cy="8" r="2" />
                      </svg>
                    )}
                  </button>
                </div>
              </div>
              <button
                type="submit"
                className="btn btn-primary"
                disabled={
                  loading ||
                  !currentPassword ||
                  !newPassword ||
                  !confirmPassword
                }
              >
                {loading ? (
                  <>
                    <span className="spinner-border spinner-border-sm mr-2" />{" "}
                    Updating...
                  </>
                ) : (
                  "Update Password"
                )}
              </button>
            </form>
          </div>
        )}
      </div>

      {/* Items Per Page Preference */}
      {currentUser.featureFlags?.user_preferences && (
        <div className="card shadow-sm mt-4">
          <div className="card-header d-flex justify-content-between align-items-center">
            <h6 className="mb-0">
              <span role="img" aria-label="settings">
                &#9881;&#65039;
              </span>{" "}
              Display Preferences
            </h6>
            {prefMessage && (
              <small
                className={
                  prefMessage === "Saved!" ? "text-success" : "text-danger"
                }
              >
                {prefMessage}
              </small>
            )}
          </div>
          <div className="card-body">
            <div className="d-flex align-items-center justify-content-between">
              <label htmlFor="itemsPerPage" className="mb-0">
                Items per page
              </label>
              <select
                id="itemsPerPage"
                className="form-control"
                style={{ width: 100 }}
                value={currentUser.itemsPerPage || 20}
                disabled={savingPreference}
                onChange={(e) =>
                  handleItemsPerPageChange(Number(e.target.value))
                }
              >
                {ALLOWED_PAGE_SIZES.map((size) => (
                  <option key={size} value={size}>
                    {size}
                  </option>
                ))}
              </select>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Profile;
